CREATE TABLE slides (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  image text NOT NULL,
  title text NOT NULL,
  subtitle text,
  buttonText text DEFAULT 'বাজার শুরু করুন',
  created_at timestamptz DEFAULT now()
);

-- ৩. orders টেবিল তৈরি করুন
CREATE TABLE orders (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  customerName text NOT NULL,
  phone text NOT NULL,
  address text NOT NULL,
  items jsonb NOT NULL,
  total float8 NOT NULL,
  status text DEFAULT 'Pending',
  date timestamptz DEFAULT now()
);

-- টেবিলগুলোতে সবার অ্যাক্সেস নিশ্চিত করতে RLS বন্ধ করুন (সহজ সেটআপের জন্য)
ALTER TABLE products DISABLE ROW LEVEL SECURITY;
ALTER TABLE slides DISABLE ROW LEVEL SECURITY;
ALTER TABLE orders DISABLE ROW LEVEL SECURITY;`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(sqlSchema);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Image Upload Helper
  const handleFileUpload = async (file: File, type: 'product' | 'slide') => {
    setIsUploading(true);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const filePath = `${type}s/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('images').getPublicUrl(filePath);

      if (type === 'product') {
        setProductForm(prev => ({ ...prev, image: data.publicUrl }));
      } else {
        setSlideForm(prev => ({ ...prev, image: data.publicUrl }));
      }
    } catch (error: any) {
      alert('ছবি আপলোড করতে সমস্যা হয়েছে! নিশ্চিত করুন যে আপনি Supabase-এ "images" নামে একটি Public Bucket তৈরি করেছেন।');
      console.error(error);
    } finally {
      setIsUploading(false);
    }
  };

  const seedDatabase = async () => {
    setIsSeeding(true);
    try {
      const productsToInsert = INITIAL_PRODUCTS.map(({ id, ...rest }) => rest);
      await supabase.from('products').insert(productsToInsert);
      const slidesToInsert = INITIAL_SLIDES.map(({ id, ...rest }) => rest);
      await supabase.from('slides').insert(slidesToInsert);
      alert('সফলভাবে ডেমো ডেটা যুক্ত করা হয়েছে! এখন পেজটি রিফ্রেশ হবে।');
      window.location.reload();
    } catch (error) {
      console.error(error);
      alert('ডেটা যুক্ত করতে সমস্যা হয়েছে।');
    } finally {
      setIsSeeding(false);
    }
  };

  const handleProductSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const data = {
      ...productForm,
      price: parseFloat(productForm.price),
      stock: parseInt(productForm.stock)
    };

    if (editingItem) {
      const { error } = await supabase.from('products').update(data).eq('id', editingItem.id);
      if (!error) {
        setProducts(prev => prev.map(p => p.id === editingItem.id ? { ...p, ...data } : p));
        setIsProductModalOpen(false);
      }
    } else {
      const { data: inserted, error } = await supabase.from('products').insert([data]).select();
      if (!error && inserted) {
        setProducts(prev => [...prev, inserted[0]]);
        setIsProductModalOpen(false);
      }
    }
    setEditingItem(null);
  };

  const handleSlideSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingItem) {
      const { error } = await supabase.from('slides').update(slideForm).eq('id', editingItem.id);
      if (!error) {
        setSlides(prev => prev.map(s => s.id === editingItem.id ? { ...s, ...slideForm } : s));
        setIsSlideModalOpen(false);
      }
    } else {
      const { data: inserted, error } = await supabase.from('slides').insert([slideForm]).select();
      if (!error && inserted) {
        setSlides(prev => [...prev, inserted[0]]);
        setIsSlideModalOpen(false);
      }
    }
    setEditingItem(null);
  };

  const deleteProduct = async (id: string) => {
    if (!confirm('আপনি কি নিশ্চিতভাবে এই পণ্যটি মুছে ফেলতে চান?')) return;
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (!error) setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSlide = async (id: string) => {
    if (!confirm('আপনি কি নিশ্চিতভাবে এই স্লাইডটি মুছে ফেলতে চান?')) return;
    const { error } = await supabase.from('slides').delete().eq('id', id);
    if (!error) setSlides(prev => prev.filter(s => s.id !== id));
  };

  const updateOrderStatus = async (id: string, status: string) => {
    const { error } = await supabase.from('orders').update({ status }).eq('id', id);
    if (!error) setOrders(prev => prev.map(o => o.id === id ? { ...o, status: status as any } : o));
  };

  if (!isAuthenticated) {
    return (
      <div className="max-w-md mx-auto my-20 p-10 bg-white rounded-3xl shadow-2xl border border-emerald-100 animate-fade-in">
        <h2 className="text-3xl font-black text-center mb-8 text-emerald-800">অ্যাডমিন প্যানেল</h2>
        <input 
          type="password" 
          className="w-full p-4 border-2 border-gray-100 rounded-2xl mb-6 focus:border-emerald-500 outline-none transition-all font-bold" 
          placeholder="পাসওয়ার্ড" 
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && password === 'admin123' && setIsAuthenticated(true)}
        />
        <button 
          onClick={() => { if (password === 'admin123') setIsAuthenticated(true); else alert('ভুল পাসওয়ার্ড'); }}
          className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          প্রবেশ করুন
        </button>
        <p className="text-center text-xs text-gray-400 mt-6 italic font-medium">পাসওয়ার্ড: admin123</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col lg:flex-row gap-8 animate-fade-in">
      {/* Sidebar */}
      <div className="w-full lg:w-64 space-y-2 shrink-0">
        <button onClick={() => setActiveTab('DASHBOARD')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'DASHBOARD' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><TrendingUp size={20} /> ড্যাশবোর্ড</button>
        <button onClick={() => setActiveTab('PRODUCTS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'PRODUCTS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Package size={20} /> পণ্য তালিকা</button>
        <button onClick={() => setActiveTab('SLIDES')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'SLIDES' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Layout size={20} /> স্লাইডার</button>
        <button onClick={() => setActiveTab('ORDERS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'ORDERS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><ClipboardList size={20} /> অর্ডারসমূহ</button>
        <button onClick={() => setActiveTab('SETTINGS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'SETTINGS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Database size={20} /> {needsSetup ? 'সেটআপ করুন' : 'সেটিংস'}</button>
        <hr className="my-6 border-gray-200" />
        <button onClick={() => setIsAuthenticated(false)} className="w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 transition-all"><LogOut size={20} /> লগআউট</button>
      </div>

      {/* Content Area */}
      <div className="flex-grow space-y-6">
        {activeTab === 'SETTINGS' && (
          <div className="space-y-6">
            <div className="bg-white p-10 rounded-3xl border-2 border-dashed border-emerald-200 shadow-sm text-center animate-fade-in">
              <Database size={60} className="mx-auto text-emerald-500 mb-6" />
              <h3 className="text-3xl font-black text-emerald-900 mb-4">ডেটাবেস ও স্টোরেজ সেটআপ</h3>

              {/* Image Upload Guide */}
              <div className="bg-emerald-50 border border-emerald-100 p-8 rounded-[2.5rem] mb-10 text-left relative overflow-hidden">
                <h4 className="text-emerald-900 text-xl font-black mb-4 flex items-center gap-2"><ImageIcon className="text-emerald-600" /> ছবি আপলোড সেটআপ:</h4>
                <div className="space-y-4">
                  <div className="flex items-start gap-4">
                    <span className="w-8 h-8 bg-emerald-600 text-white rounded-full flex items-center justify-center shrink-0 font-bold text-sm">১</span>
                    <p className="text-emerald-800 font-medium leading-relaxed">Supabase ড্যাশবোর্ডে গিয়ে বাম পাশের <b>Storage</b> মেনুতে যান।</p>
                  </div>
                  <div className="flex items-start gap-4">
                    <span className="w-8 h-8 bg-emerald-600 text-white rounded-full flex items-center justify-center shrink-0 font-bold text-sm">২</span>
                    <p className="text-emerald-800 font-medium leading-relaxed"><b>New Bucket</b> বাটনে ক্লিক করুন এবং নাম দিন <b>images</b>।</p>
                  </div>
                  <div className="flex items-start gap-4">
                    <span className="w-8 h-8 bg-emerald-600 text-white rounded-full flex items-center justify-center shrink-0 font-bold text-sm">৩</span>
                    <p className="text-emerald-800 font-medium leading-relaxed">বাকেটটি অবশ্যই <b>Public</b> হিসেবে সেট করুন যাতে সবাই ছবি দেখতে পারে।</p>
                  </div>
                </div>
              </div>

              <div className="relative mb-10 text-left">
                <div className="absolute top-4 right-4 z-10 flex gap-2">
                  <button onClick={copyToClipboard} className="flex items-center gap-2 bg-emerald-100 text-emerald-700 px-4 py-2 rounded-xl text-xs font-bold hover:bg-emerald-200 transition-all shadow-sm">
                    {copied ? <><CheckCircle2 size={16}/> কপি হয়েছে</> : <><Copy size={16}/> SQL কোড কপি করুন</>}
                  </button>
                </div>
                <pre className="bg-gray-950 text-emerald-400 p-8 rounded-3xl overflow-x-auto text-sm font-mono leading-relaxed border-4 border-emerald-500/10 shadow-2xl">
                  {sqlSchema}
                </pre>
              </div>

              <div className="flex flex-col sm:flex-row gap-4 justify-center">
                <button 
                  disabled={isSeeding}
                  onClick={seedDatabase}
                  className={`bg-emerald-600 text-white px-12 py-5 rounded-2xl font-black text-xl shadow-xl shadow-emerald-200 transition-all active:scale-95 flex items-center justify-center gap-3 ${isSeeding ? 'opacity-50 cursor-not-allowed' : ''}`}
                >
                  {isSeeding ? <><RefreshCw size={24} className="animate-spin"/> প্রসেসিং...</> : 'ডেমো ডেটা ইনজেক্ট করুন'}
                </button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'DASHBOARD' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mb-2">মোট বিক্রয়</p>
              <p className="text-4xl font-black text-emerald-700">৳ {orders.reduce((s, o) => s + o.total, 0)}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mb-2">মোট অর্ডার</p>
              <p className="text-4xl font-black">{orders.length}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mb-2">পণ্য সংখ্যা</p>
              <p className="text-4xl font-black">{products.length}</p>
            </div>
          </div>
        )}

        {activeTab === 'PRODUCTS' && (
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
              <h3 className="text-xl font-bold text-gray-800">পণ্যের তালিকা</h3>
              <button 
                onClick={() => { setEditingItem(null); setProductForm({name:'', price:'', unit:'কেজি', category: Category.VEGETABLES, image:'', description:'', stock:'100'}); setIsProductModalOpen(true); }}
                className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-emerald-700 transition-all shadow-md"
              >
                <Plus size={18}/> নতুন পণ্য
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  <tr><th className="p-6 text-left">নাম</th><th className="p-6 text-left">ক্যাটাগরি</th><th className="p-6 text-right">দাম</th><th className="p-6 text-right">অ্যাকশন</th></tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="p-6 font-bold text-gray-700">{p.name}</td>
                      <td className="p-6 text-sm text-gray-500 font-medium">{p.category}</td>
                      <td className="p-6 text-right font-black text-emerald-800">৳ {p.price}</td>
                      <td className="p-6 text-right space-x-2">
                        <button onClick={() => { setEditingItem(p); setProductForm({name:p.name, price:p.price.toString(), unit:p.unit, category:p.category, image:p.image, description:p.description, stock:p.stock.toString()}); setIsProductModalOpen(true); }} className="text-blue-500 hover:bg-blue-50 p-2 rounded-xl transition-all"><Edit size={18}/></button>
                        <button onClick={() => deleteProduct(p.id)} className="text-red-500 hover:bg-red-50 p-2 rounded-xl transition-all"><Trash2 size={18}/></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeTab === 'SLIDES' && (
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
              <h3 className="text-xl font-bold text-gray-800">স্লাইডার ম্যানেজমেন্ট</h3>
              <button 
                onClick={() => { setEditingItem(null); setSlideForm({image:'', title:'', subtitle:'', buttonText:'বাজার শুরু করুন'}); setIsSlideModalOpen(true); }}
                className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2"
              >
                <Plus size={18}/> নতুন স্লাইড
              </button>
            </div>
            <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
              {slides.map(s => (
                <div key={s.id} className="group relative rounded-2xl overflow-hidden border border-gray-100 shadow-sm">
                  <img src={s.image} className="w-full h-40 object-cover opacity-80" alt="" />
                  <div className="p-4">
                    <h4 className="font-bold text-lg">{s.title}</h4>
                    <p className="text-sm text-gray-500 line-clamp-1">{s.subtitle}</p>
                    <div className="mt-4 flex gap-2">
                      <button onClick={() => { setEditingItem(s); setSlideForm({image:s.image, title:s.title, subtitle:s.subtitle, buttonText:s.buttonText}); setIsSlideModalOpen(true); }} className="flex-1 bg-blue-50 text-blue-600 py-2 rounded-xl font-bold text-xs flex justify-center items-center gap-1"><Edit size={14}/> এডিট</button>
                      <button onClick={() => deleteSlide(s.id)} className="flex-1 bg-red-50 text-red-600 py-2 rounded-xl font-bold text-xs flex justify-center items-center gap-1"><Trash2 size={14}/> ডিলিট</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'ORDERS' && (
          <div className="space-y-4">
            {orders.length === 0 ? <p className="text-center py-20 bg-white rounded-3xl border text-gray-400 font-bold">কোনো অর্ডার পাওয়া যায়নি</p> : orders.map(o => (
              <div key={o.id} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                  <div className="flex items-center gap-3 mb-1">
                    <p className="font-black text-xl text-emerald-900">{o.customerName}</p>
                    <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-full ${o.status === 'Delivered' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                      {o.status === 'Pending' ? 'অপেক্ষমান' : 'ডেলিভারি সম্পন্ন'}
                    </span>
                  </div>
                  <p className="text-sm text-gray-500 font-bold">{o.phone} • {o.address}</p>
                  <p className="text-xs text-gray-400 mt-1">{new Date(o.date).toLocaleString('bn-BD')}</p>
                </div>
                <div className="text-left md:text-right w-full md:w-auto">
                  <p className="text-2xl font-black text-emerald-800 mb-2">৳ {o.total}</p>
                  {o.status === 'Pending' && (
                    <button onClick={() => updateOrderStatus(o.id, 'Delivered')} className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-md shadow-emerald-100">ডেলিভারি সম্পন্ন</button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Product Modal */}
      {isProductModalOpen && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-fade-in">
            <div className="p-6 border-b flex justify-between items-center bg-emerald-50">
              <h3 className="font-black text-emerald-900 text-xl">{editingItem ? 'পণ্য সম্পাদনা' : 'নতুন পণ্য যোগ করুন'}</h3>
              <button onClick={() => setIsProductModalOpen(false)}><X size={20}/></button>
            </div>
            <form onSubmit={handleProductSubmit} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">পণ্যের নাম</label>
                <input required value={productForm.name} onChange={e => setProductForm({...productForm, name: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">ক্যাটাগরি</label>
                <select value={productForm.category} onChange={e => setProductForm({...productForm, category: e.target.value as Category})} className="w-full p-3 bg-gray-50 border rounded-xl">
                  {Object.values(Category).filter(c => c !== Category.ALL).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">দাম (৳)</label>
                <input required type="number" value={productForm.price} onChange={e => setProductForm({...productForm, price: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">একক (Unit)</label>
                <input required value={productForm.unit} onChange={e => setProductForm({...productForm, unit: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>

              <div className="md:col-span-2 space-y-2">
                <label className="text-xs font-bold text-gray-400 uppercase">পণ্যের ছবি</label>
                <div className="flex gap-4 items-center">
                  <label className={`flex-grow flex items-center justify-center gap-2 border-2 border-dashed rounded-xl p-4 cursor-pointer transition-all ${isUploading ? 'bg-gray-50 opacity-50' : 'hover:border-emerald-500 hover:bg-emerald-50'}`}>
                    <input 
                      type="file" 
                      className="hidden" 
                      accept="image/*"
                      disabled={isUploading}
                      onChange={(e) => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'product')} 
                    />
                    {isUploading ? <><RefreshCw size={18} className="animate-spin"/> আপলোড হচ্ছে...</> : <><Upload size={18}/> ছবি সিলেক্ট করুন</>}
                  </label>
                  {productForm.image && <img src={productForm.image} className="w-16 h-16 rounded-xl object-cover border" alt="Preview" />}
                </div>
                <input value={productForm.image} onChange={e => setProductForm({...productForm, image: e.target.value})} className="w-full p-2 bg-gray-50 border rounded-lg text-[10px]" placeholder="অথবা ছবির সরাসরি লিংক এখানে দিন" />
              </div>

              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">বর্ণনা</label>
                <textarea rows={2} value={productForm.description} onChange={e => setProductForm({...productForm, description: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <div className="md:col-span-2 pt-4">
                <button type="submit" disabled={isUploading} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg flex items-center justify-center gap-2">
                  <Save size={20}/> {editingItem ? 'আপডেট করুন' : 'সেভ করুন'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Slide Modal */}
      {isSlideModalOpen && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden animate-fade-in">
            <div className="p-6 border-b flex justify-between items-center bg-emerald-50">
              <h3 className="font-black text-emerald-900 text-xl">{editingItem ? 'স্লাইড সম্পাদনা' : 'নতুন স্লাইড'}</h3>
              <button onClick={() => setIsSlideModalOpen(false)}><X size={20}/></button>
            </div>
            <form onSubmit={handleSlideSubmit} className="p-8 space-y-4">
              <div className="space-y-2">
                <label className="text-xs font-bold text-gray-400 uppercase">স্লাইড ছবি</label>
                <div className="flex gap-4 items-center">
                  <label className="flex-grow flex items-center justify-center gap-2 border-2 border-dashed rounded-xl p-6 cursor-pointer hover:bg-emerald-50">
                    <input 
                      type="file" 
                      className="hidden" 
                      accept="image/*"
                      onChange={(e) => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'slide')} 
                    />
                    {isUploading ? <RefreshCw size={24} className="animate-spin"/> : <Upload size={24}/>}
                    <span>{isUploading ? 'আপলোড হচ্ছে...' : 'ক্লিক করে আপলোড করুন'}</span>
                  </label>
                </div>
                {slideForm.image && <p className="text-[10px] text-emerald-600 font-bold truncate">ইউআরএল: {slideForm.image}</p>}
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">টাইটেল</label>
                <input required value={slideForm.title} onChange={e => setSlideForm({...slideForm, title: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">সাব-টাইটেল</label>
                <input value={slideForm.subtitle} onChange={e => setSlideForm({...slideForm, subtitle: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <button type="submit" disabled={isUploading} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg">
                {editingItem ? 'আপডেট' : 'সেভ'} করুন
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ShoppingCart, Store, Info, Phone, Search, Menu, X, ArrowRight, Settings, CheckCircle, MapPin, Heart, AlertTriangle, Eye } from 'lucide-react';
import { ViewType, Category, Product, CartItem, Order, Slide } from './types';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from './data';
import { supabase } from './supabase';
import AdminPanel from './components/AdminPanel';
import CartSidebar from './components/CartSidebar';
import ProductCard from './components/ProductCard';
import confetti from 'canvas-confetti';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType | 'ORDER_SUCCESS' | 'SETUP_REQUIRED'>('STORE');
  const [products, setProducts] = useState<Product[]>([]);
  const [slides, setSlides] = useState<Slide[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isCartBouncing, setIsCartBouncing] = useState(false);

  const refreshData = async () => {
    setIsLoading(true);
    setDbError(null);
    try {
      const { data: prodData, error: prodError } = await supabase.from('products').select('*');
      const { data: slideData, error: slideError } = await supabase.from('slides').select('*');
      const { data: orderData } = await supabase.from('orders').select('*').order('date', { ascending: false });

      if (prodError?.code === '42P01' || slideError?.code === '42P01') {
        setDbError('DATABASE_TABLES_MISSING');
        setView('SETUP_REQUIRED');
        return;
      }

      if (prodData && prodData.length > 0) setProducts(prodData);
      else setProducts(INITIAL_PRODUCTS);

      if (slideData && slideData.length > 0) setSlides(slideData);
      else setSlides(INITIAL_SLIDES);

      if (orderData) setOrders(orderData);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  useEffect(() => {
    if (view === 'STORE' && slides.length > 0) {
      const timer = setInterval(() => {
        setCurrentSlide(prev => (prev + 1) % slides.length);
      }, 5000);
      return () => clearInterval(timer);
    }
  }, [view, slides.length]);

  const addToCart = useCallback((product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { product, quantity: 1 }];
    });

    // Bounce feedback
    setIsCartBouncing(true);
    setTimeout(() => setIsCartBouncing(false), 500);
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  }, []);

  const updateQuantity = useCallback((productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  }, []);

  const cartTotal = useMemo(() => cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0), [cart]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = activeCategory === Category.ALL || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [products, activeCategory, searchQuery]);

  const placeOrder = async (customerData: { name: string, phone: string, address: string }) => {
    const newOrder = {
      customerName: customerData.name,
      phone: customerData.phone,
      address: customerData.address,
      items: cart,
      total: cartTotal,
      status: 'Pending',
      date: new Date().toISOString()
    };

    const { data, error } = await supabase.from('orders').insert([newOrder]).select();

    if (error) {
      alert('অর্ডার সেভ করতে সমস্যা হয়েছে। দয়া করে আপনার ইন্টারনেট কানেকশন চেক করুন।');
    } else {
      setOrders(prev => [data[0], ...prev]);
      setCart([]);
      setView('ORDER_SUCCESS');
      confetti({
        particleCount: 150,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#059669', '#10b981', '#34d399', '#ffffff']
      });
    }
  };

  const NavItem: React.FC<{ label: string; viewTarget: ViewType; icon?: React.ReactNode }> = ({ label, viewTarget, icon }) => (
    <button 
      onClick={() => { setView(viewTarget); setIsMobileMenuOpen(false); window.scrollTo(0,0); }}
      className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-bold transition-all duration-300 ${
        view === viewTarget ? 'text-emerald-700 bg-emerald-50 shadow-sm border border-emerald-100' : 'text-gray-500 hover:text-emerald-600 hover:bg-gray-50'
      }`}
    >
      {icon}
      <span>{label}</span>
    </button>
  );

  if (isLoading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-white">
        <div className="w-16 h-16 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-emerald-800 font-bold animate-pulse tracking-widest">লোডিং হচ্ছে...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col selection:bg-emerald-100">
      {/* Top Banner */}
      <div className="bg-emerald-800 text-white text-[10px] md:text-xs py-2 px-4 text-center font-bold tracking-wider uppercase">
        বদলগাছী সদরে ১ ঘণ্টার মধ্যে হোম ডেলিভারি ফ্রি! আজই অর্ডার করুন।
      </div>

      <header className="sticky top-0 z-40 bg-white/95 backdrop-blur-md border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20 gap-4">
            {/* Logo */}
            <div className="flex items-center gap-4 cursor-pointer shrink-0" onClick={() => setView('STORE')}>
              <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-100 transition-transform active:scale-90"><Store size={26} /></div>
              <div className="hidden sm:block">
                <h1 className="text-xl font-black text-emerald-900 leading-none">সামসুল'স গ্রোসরি</h1>
                <p className="text-[10px] text-gray-400 font-bold mt-1 flex items-center gap-1 uppercase tracking-tighter"><MapPin size={10}/> বদলগাছী, নওগাঁ</p>
              </div>
            </div>

            {/* Search Bar - Desktop */}
            {view === 'STORE' && (
              <div className="hidden md:flex flex-grow max-w-xl relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-500 transition-colors" size={18} />
                <input 
                  type="text"
                  placeholder="আপনার প্রিয় পণ্যটি খুঁজুন..."
                  className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl py-3 pl-12 pr-4 outline-none transition-all font-medium text-sm shadow-inner"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
            )}

            {/* Actions */}
            <div className="flex items-center gap-2 md:gap-4">
              <nav className="hidden lg:flex items-center gap-1">
                <NavItem label="হোম" viewTarget="STORE" icon={<Store size={18} />} />
                <NavItem label="আমাদের কথা" viewTarget="ABOUT" icon={<Info size={18} />} />
                <NavItem label="অ্যাডমিন" viewTarget="ADMIN" icon={<Settings size={18} />} />
              </nav>

              <div className="h-8 w-[1px] bg-gray-200 hidden lg:block mx-2"></div>

              <button 
                onClick={() => setIsCartOpen(true)} 
                className={`group relative p-3 text-gray-700 hover:bg-emerald-50 rounded-2xl transition-all active:scale-95 ${isCartBouncing ? 'animate-bounce' : ''}`}
              >
                <ShoppingCart size={24} className="group-hover:text-emerald-600" />
                {cart.length > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-black w-6 h-6 flex items-center justify-center rounded-full border-4 border-white shadow-sm animate-fade-in">
                    {cart.length}
                  </span>
                )}
              </button>

              <button 
                className="lg:hidden p-3 text-gray-700 hover:bg-gray-100 rounded-2xl" 
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Floating Cart Button for Mobile */}
      {cart.length > 0 && !isCartOpen && view === 'STORE' && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className={`fixed bottom-6 right-6 z-50 md:hidden bg-emerald-600 text-white p-5 rounded-full shadow-2xl flex items-center gap-3 animate-fade-in ${isCartBouncing ? 'scale-110' : 'scale-100'} transition-transform`}
        >
          <div className="relative">
            <ShoppingCart size={24} />
            <span className="absolute -top-4 -right-4 bg-red-500 text-white text-[10px] font-black w-6 h-6 flex items-center justify-center rounded-full border-2 border-emerald-600">{cart.length}</span>
          </div>
          <span className="font-black">৳ {cartTotal}</span>
        </button>
      )}

      {/* Mobile Navigation Drawer */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 top-20 bg-white z-50 p-6 animate-fade-in border-t shadow-2xl">
          <nav className="flex flex-col gap-3">
            <NavItem label="হোম পেজ" viewTarget="STORE" icon={<Store size={22} />} />
            <NavItem label="আমাদের সম্পর্কে" viewTarget="ABOUT" icon={<Info size={22} />} />
            <NavItem label="অ্যাডমিন প্যানেল" viewTarget="ADMIN" icon={<Settings size={22} />} />
          </nav>
        </div>
      )}

      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="animate-fade-in">
            {/* Hero Slider */}
            <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8">
              {slides.length > 0 && (
                <div className="relative rounded-[2.5rem] overflow-hidden mb-10 h-72 md:h-[500px] shadow-2xl bg-emerald-900 group">
                  {slides.map((slide, index) => (
                    <div key={slide.id} className={`absolute inset-0 transition-all duration-1000 ease-out ${index === currentSlide ? 'opacity-100 scale-100' : 'opacity-0 scale-105 pointer-events-none'}`}>
                      <img src={slide.image} alt={slide.title} className="w-full h-full object-cover opacity-50" />
                      <div className="absolute inset-0 bg-gradient-to-r from-emerald-950/95 via-emerald-900/40 to-transparent flex flex-col justify-center px-8 md:px-20">
                        <span className="text-emerald-400 font-black text-xs md:text-sm uppercase tracking-[0.4em] mb-4">সামসুল'স গ্রোসরি স্পেশাল</span>
                        <h2 className="text-3xl md:text-6xl font-black text-white mb-6 leading-tight max-w-2xl">{slide.title}</h2>
                        <p className="text-emerald-100/90 text-sm md:text-xl mb-10 max-w-lg leading-relaxed font-medium">{slide.subtitle}</p>
                        <button 
                          onClick={() => {
                            const productsSection = document.getElementById('products-grid');
                            productsSection?.scrollIntoView({ behavior: 'smooth' });
                          }} 
                          className="bg-white text-emerald-900 px-10 py-4 rounded-2xl font-black w-fit hover:bg-emerald-50 transition-all shadow-xl"
                        >
                          {slide.buttonText}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {/* Category Filter */}
              <div className="mb-10">
                <div className="flex gap-4 overflow-x-auto no-scrollbar pb-4 -mx-4 px-4">
                  {Object.values(Category).map(cat => (
                    <button
                      key={cat}
                      onClick={() => setActiveCategory(cat)}
                      className={`px-8 py-3.5 rounded-2xl font-black whitespace-nowrap transition-all border-2 text-sm ${
                        activeCategory === cat 
                        ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200' 
                        : 'bg-white border-gray-100 text-gray-500 hover:border-emerald-200 hover:text-emerald-600'
                      }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>

              {/* Product Grid */}
              <div id="products-grid" className="scroll-mt-32">
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 md:gap-8">
                  {filteredProducts.map(product => (
                    <ProductCard 
                      key={product.id} 
                      product={product} 
                      onAddToCart={addToCart} 
                      onQuickView={() => setSelectedProduct(product)}
                    />
                  ))}
                </div>
                {filteredProducts.length === 0 && (
                  <div className="py-24 text-center">
                    <p className="text-2xl font-black text-gray-400">দুঃখিত, কোনো পণ্য পাওয়া যায়নি!</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {view === 'CHECKOUT' && (
          <div className="max-w-xl mx-auto py-20 px-4 animate-fade-in">
            <h2 className="text-4xl font-black mb-10 text-center text-emerald-900">চেকআউট</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              placeOrder({
                name: fd.get('name') as string,
                phone: fd.get('phone') as string,
                address: fd.get('address') as string,
              });
            }} className="bg-white p-10 rounded-[3rem] shadow-2xl space-y-6">
              <input name="name" required className="w-full p-4 bg-gray-50 border rounded-2xl font-bold" placeholder="আপনার নাম" />
              <input name="phone" required type="tel" className="w-full p-4 bg-gray-50 border rounded-2xl font-bold" placeholder="মোবাইল নম্বর" />
              <textarea name="address" required className="w-full p-4 bg-gray-50 border rounded-2xl font-bold" placeholder="ঠিকানা" rows={3}></textarea>
              <div className="pt-6 border-t">
                <div className="flex justify-between items-center mb-6">
                  <span className="text-gray-500 font-bold">মোট দেয়:</span>
                  <span className="text-3xl font-black text-emerald-800">৳ {cartTotal}</span>
                </div>
                <button className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl hover:bg-emerald-700 transition-all">
                  অর্ডার সম্পন্ন করুন
                </button>
              </div>
            </form>
          </div>
        )}

        {view === 'ORDER_SUCCESS' && (
          <div className="max-w-2xl mx-auto py-32 px-4 text-center animate-fade-in">
            <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 shadow-2xl">
              <CheckCircle size={72} strokeWidth={2.5} />
            </div>
            <h2 className="text-5xl font-black text-emerald-900 mb-6 tracking-tight">অর্ডার সফল হয়েছে!</h2>
            <p className="text-gray-500 text-xl mb-12 font-medium">আমরা খুব শীঘ্রই ডেলিভারির জন্য আপনার সাথে যোগাযোগ করব।</p>
            <button onClick={() => setView('STORE')} className="bg-emerald-600 text-white px-12 py-5 rounded-2xl font-black text-xl shadow-xl hover:bg-emerald-700 transition-all shadow-emerald-200">আরো বাজার করুন</button>
          </div>
        )}

        {view === 'ADMIN' && (
          <AdminPanel 
            products={products} setProducts={setProducts} 
            slides={slides} setSlides={setSlides}
            orders={orders} setOrders={setOrders}
            needsSetup={dbError === 'DATABASE_TABLES_MISSING'}
          />
        )}

        {view === 'ABOUT' && (
          <div className="max-w-4xl mx-auto py-20 px-6 animate-fade-in text-center">
            <h2 className="text-5xl font-black text-emerald-900 mb-10">আমাদের সম্পর্কে</h2>
            <p className="text-xl text-gray-600 leading-relaxed max-w-2xl mx-auto font-medium">বদলগাছীর সাধারণ মানুষের নিত্যদিনের বাজারকে সহজ ও আধুনিক করতে আমাদের পথচলা। আমরা সরাসরি খামারিদের থেকে তাজা পণ্য আপনার কাছে পৌঁছে দিই। আপনার সুস্বাস্থ্যই আমাদের সার্থকতা।</p>
          </div>
        )}

        {view === 'SETUP_REQUIRED' && (
          <div className="min-h-screen bg-emerald-50 flex items-center justify-center p-6">
            <div className="max-w-2xl w-full bg-white rounded-[3rem] shadow-2xl p-12 text-center">
              <AlertTriangle size={48} className="text-amber-500 mx-auto mb-8" />
              <h2 className="text-4xl font-black text-emerald-900 mb-4">সেটআপ প্রয়োজন</h2>
              <p className="text-gray-500 mb-10 font-medium">প্রথমে আপনার ডাটাবেস টেবিলগুলো তৈরি করে ডেমো ডাটা যুক্ত করুন।</p>
              <button onClick={() => setView('ADMIN')} className="bg-emerald-600 text-white px-10 py-4 rounded-2xl font-black text-xl shadow-lg shadow-emerald-100">অ্যাডমিন প্যানেলে যান</button>
            </div>
          </div>
        )}
      </main>

      {/* Product Detail Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-fade-in flex flex-col md:flex-row max-h-[90vh] overflow-y-auto">
            <div className="w-full md:w-1/2 aspect-square relative">
              <img src={selectedProduct.image} alt={selectedProduct.name} className="w-full h-full object-cover" />
              <button onClick={() => setSelectedProduct(null)} className="absolute top-6 left-6 bg-white/80 p-2 rounded-full md:hidden shadow-lg"><X/></button>
            </div>
            <div className="w-full md:w-1/2 p-10 flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-4">
                  <span className="bg-emerald-100 text-emerald-700 px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProduct.category}</span>
                  <button onClick={() => setSelectedProduct(null)} className="hidden md:block p-2 hover:bg-gray-100 rounded-full transition-all"><X/></button>
                </div>
                <h3 className="text-3xl font-black text-gray-900 mb-2">{selectedProduct.name}</h3>
                <p className="text-gray-500 font-medium mb-6 leading-relaxed text-lg">{selectedProduct.description}</p>
                <div className="flex items-end gap-2 mb-10">
                  <span className="text-4xl font-black text-emerald-800">৳ {selectedProduct.price}</span>
                  <span className="text-gray-400 font-bold mb-1">প্রতি {selectedProduct.unit}</span>
                </div>
              </div>
              <button 
                onClick={() => { addToCart(selectedProduct); setSelectedProduct(null); setIsCartOpen(true); }}
                className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl shadow-emerald-200 hover:bg-emerald-700 active:scale-95 transition-all flex items-center justify-center gap-3"
              >
                <ShoppingCart /> ব্যাগে যোগ করুন
              </button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-gray-950 text-white py-20 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <h1 className="text-3xl font-black mb-4 tracking-tight">সামসুল'স গ্রোসরি</h1>
          <p className="text-gray-400 mb-8 font-medium">বদলগাছী বাজার, বদলগাছী, নওগাঁ, বাংলাদেশ</p>
          <div className="flex justify-center gap-6 mb-12">
            <a href="tel:01700000000" className="flex items-center gap-2 text-emerald-400 font-bold hover:scale-105 transition-transform"><Phone size={20}/> ০১৭০০-০০০০০০</a>
          </div>
          <p className="text-[10px] text-gray-600 uppercase tracking-[0.4em] font-bold">© ২০২৪ সকল স্বত্ব সংরক্ষিত</p>
        </div>
      </footer>

      <CartSidebar 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} 
        cart={cart} updateQuantity={updateQuantity} 
        removeFromCart={removeFromCart} onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Package, ClipboardList, TrendingUp, LogOut, Plus, Trash2, X, Edit, Layout, Save, Database, Copy, CheckCircle2, AlertTriangle, RefreshCw, Upload, Image as ImageIcon, CheckCircle } from 'lucide-react';
import { Product, Order, Slide, Category } from '../types';
import { supabase } from '../supabase';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from '../data';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  slides: Slide[];
  setSlides: React.Dispatch<React.SetStateAction<Slide[]>>;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  needsSetup?: boolean;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ products, setProducts, slides, setSlides, orders, setOrders, needsSetup = false }) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'PRODUCTS' | 'ORDERS' | 'SLIDES' | 'SETTINGS'>(needsSetup ? 'SETTINGS' : 'DASHBOARD');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [isSeeding, setIsSeeding] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [copied, setCopied] = useState(false);

  // Modals state
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isSlideModalOpen, setIsSlideModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);

  // Form states
  const [productForm, setProductForm] = useState({
    name: '', price: '', unit: 'কেজি', category: Category.VEGETABLES, image: '', description: '', stock: '100'
  });
  const [slideForm, setSlideForm] = useState({
    image: '', title: '', subtitle: '', buttonText: 'বাজার শুরু করুন'
  });

  const sqlSchema = `-- ১. products টেবিল তৈরি করুন
CREATE TABLE products (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  price float8 NOT NULL,
  unit text NOT NULL,
  category text NOT NULL,
  image text,
  description text,
  stock int4 DEFAULT 100,
  created_at timestamptz DEFAULT now()
);

-- ২. slides টেবিল তৈরি করুন
CREATE TABLE slides (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  image text NOT NULL,
  title text NOT NULL,
  subtitle text,
  buttonText text DEFAULT 'বাজার শুরু করুন',
  created_at timestamptz DEFAULT now()
);

-- ৩. orders টেবিল তৈরি করুন
CREATE TABLE orders (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  customerName text NOT NULL,
  phone text NOT NULL,
  address text NOT NULL,
  items jsonb NOT NULL,
  total float8 NOT NULL,
  status text DEFAULT 'Pending',
  date timestamptz DEFAULT now()
);

-- টেবিলগুলোতে সবার অ্যাক্সেস নিশ্চিত করতে RLS বন্ধ করুন
ALTER TABLE products DISABLE ROW LEVEL SECURITY;
ALTER TABLE slides DISABLE ROW LEVEL SECURITY;
ALTER TABLE orders DISABLE ROW LEVEL SECURITY;`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(sqlSchema);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Image Upload Helper with unique filenames
  const handleFileUpload = async (file: File, type: 'product' | 'slide') => {
    setIsUploading(true);
    try {
      const fileExt = file.name.split('.').pop();
      // Added a timestamp for guaranteed uniqueness
      const fileName = `${Date.now()}-${Math.floor(Math.random() * 1000)}.${fileExt}`;
      const filePath = `${type}s/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file, {
          cacheControl: '3600',
          upsert: false
        });

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('images').getPublicUrl(filePath);

      if (type === 'product') {
        setProductForm(prev => ({ ...prev, image: data.publicUrl }));
      } else {
        setSlideForm(prev => ({ ...prev, image: data.publicUrl }));
      }
    } catch (error: any) {
      alert('ছবি আপলোড করতে সমস্যা হয়েছে! নিশ্চিত করুন যে আপনি Supabase Storage-এ "images" নামে একটি Public Bucket তৈরি করেছেন।');
      console.error(error);
    } finally {
      setIsUploading(false);
    }
  };

  const seedDatabase = async () => {
    setIsSeeding(true);
    try {
      const productsToInsert = INITIAL_PRODUCTS.map(({ id, ...rest }) => rest);
      await supabase.from('products').insert(productsToInsert);
      const slidesToInsert = INITIAL_SLIDES.map(({ id, ...rest }) => rest);
      await supabase.from('slides').insert(slidesToInsert);
      alert('সফলভাবে ডেমো ডেটা যুক্ত করা হয়েছে!');
      window.location.reload();
    } catch (error) {
      console.error(error);
      alert('ডেটা যুক্ত করতে সমস্যা হয়েছে।');
    } finally {
      setIsSeeding(false);
    }
  };

  const handleProductSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!productForm.image) return alert('অনুগ্রহ করে পণ্যের ছবি যোগ করুন।');

    const data = {
      ...productForm,
      price: parseFloat(productForm.price),
      stock: parseInt(productForm.stock)
    };

    if (editingItem) {
      const { error } = await supabase.from('products').update(data).eq('id', editingItem.id);
      if (!error) {
        setProducts(prev => prev.map(p => p.id === editingItem.id ? { ...p, ...data } : p));
        setIsProductModalOpen(false);
      }
    } else {
      const { data: inserted, error } = await supabase.from('products').insert([data]).select();
      if (!error && inserted) {
        setProducts(prev => [...prev, inserted[0]]);
        setIsProductModalOpen(false);
      }
    }
    setEditingItem(null);
  };

  const handleSlideSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!slideForm.image) return alert('স্লাইড ছবি আবশ্যিক।');

    if (editingItem) {
      const { error } = await supabase.from('slides').update(slideForm).eq('id', editingItem.id);
      if (!error) {
        setSlides(prev => prev.map(s => s.id === editingItem.id ? { ...s, ...slideForm } : s));
        setIsSlideModalOpen(false);
      }
    } else {
      const { data: inserted, error } = await supabase.from('slides').insert([slideForm]).select();
      if (!error && inserted) {
        setSlides(prev => [...prev, inserted[0]]);
        setIsSlideModalOpen(false);
      }
    }
    setEditingItem(null);
  };

  const deleteProduct = async (id: string) => {
    if (!confirm('আপনি কি নিশ্চিতভাবে এই পণ্যটি মুছে ফেলতে চান?')) return;
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (!error) setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSlide = async (id: string) => {
    if (!confirm('আপনি কি নিশ্চিতভাবে এই স্লাইডটি মুছে ফেলতে চান?')) return;
    const { error } = await supabase.from('slides').delete().eq('id', id);
    if (!error) setSlides(prev => prev.filter(s => s.id !== id));
  };

  const updateOrderStatus = async (id: string, status: string) => {
    const { error } = await supabase.from('orders').update({ status }).eq('id', id);
    if (!error) setOrders(prev => prev.map(o => o.id === id ? { ...o, status: status as any } : o));
  };

  if (!isAuthenticated) {
    return (
      <div className="max-w-md mx-auto my-20 p-10 bg-white rounded-3xl shadow-2xl border border-emerald-100 animate-fade-in">
        <h2 className="text-3xl font-black text-center mb-8 text-emerald-800 tracking-tight">অ্যাডমিন প্যানেল</h2>
        <input 
          type="password" 
          className="w-full p-4 border-2 border-gray-100 rounded-2xl mb-6 focus:border-emerald-500 outline-none transition-all font-bold" 
          placeholder="পাসওয়ার্ড লিখুন" 
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && password === 'admin123' && setIsAuthenticated(true)}
        />
        <button 
          onClick={() => { if (password === 'admin123') setIsAuthenticated(true); else alert('ভুল পাসওয়ার্ড'); }}
          className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          প্রবেশ করুন
        </button>
        <p className="text-center text-xs text-gray-400 mt-6 italic font-bold">পাসওয়ার্ড: admin123</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col lg:flex-row gap-8 animate-fade-in">
      {/* Sidebar */}
      <div className="w-full lg:w-64 space-y-2 shrink-0">
        <button onClick={() => setActiveTab('DASHBOARD')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'DASHBOARD' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><TrendingUp size={20} /> ড্যাশবোর্ড</button>
        <button onClick={() => setActiveTab('PRODUCTS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'PRODUCTS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Package size={20} /> পণ্য তালিকা</button>
        <button onClick={() => setActiveTab('SLIDES')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'SLIDES' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Layout size={20} /> স্লাইডার</button>
        <button onClick={() => setActiveTab('ORDERS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'ORDERS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><ClipboardList size={20} /> অর্ডারসমূহ</button>
        <button onClick={() => setActiveTab('SETTINGS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'SETTINGS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Database size={20} /> সেটিংস</button>
        <hr className="my-6 border-gray-200" />
        <button onClick={() => setIsAuthenticated(false)} className="w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 transition-all"><LogOut size={20} /> লগআউট</button>
      </div>

      {/* Content Area */}
      <div className="flex-grow space-y-6">
        {activeTab === 'SETTINGS' && (
          <div className="space-y-6">
            <div className="bg-white p-10 rounded-3xl border border-gray-100 shadow-sm text-center animate-fade-in">
              <Database size={60} className="mx-auto text-emerald-500 mb-6" />
              <h3 className="text-3xl font-black text-emerald-900 mb-4">সেটআপ ও সেটিংস</h3>

              <div className="bg-emerald-50 border border-emerald-100 p-8 rounded-[2.5rem] mb-10 text-left relative overflow-hidden">
                <h4 className="text-emerald-900 text-xl font-black mb-4 flex items-center gap-2"><CheckCircle className="text-emerald-600" /> স্ট্যাটাস চেক:</h4>
                <p className="text-emerald-800 font-medium leading-relaxed">১. আপনি সফলভাবে <b>'images'</b> বাকেট তৈরি করেছেন।<br/> ২. এখন আপনি পণ্য যোগ করার সময় সরাসরি গ্যালারি থেকে ছবি দিতে পারবেন।</p>
              </div>

              <div className="relative mb-10 text-left">
                <div className="absolute top-4 right-4 z-10 flex gap-2">
                  <button onClick={copyToClipboard} className="flex items-center gap-2 bg-emerald-100 text-emerald-700 px-4 py-2 rounded-xl text-xs font-bold hover:bg-emerald-200 transition-all shadow-sm">
                    {copied ? <><CheckCircle2 size={16}/> কপি হয়েছে</> : <><Copy size={16}/> SQL কপি করুন</>}
                  </button>
                </div>
                <pre className="bg-gray-950 text-emerald-400 p-8 rounded-3xl overflow-x-auto text-xs font-mono border-4 border-emerald-500/10 shadow-xl">
                  {sqlSchema}
                </pre>
              </div>

              <button 
                disabled={isSeeding}
                onClick={seedDatabase}
                className={`bg-emerald-600 text-white px-12 py-5 rounded-2xl font-black text-xl shadow-xl shadow-emerald-200 transition-all active:scale-95 flex items-center justify-center gap-3 mx-auto ${isSeeding ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                {isSeeding ? <><RefreshCw size={24} className="animate-spin"/> প্রসেসিং...</> : 'ডেমো ডেটা রিস্টোর করুন'}
              </button>
            </div>
          </div>
        )}

        {activeTab === 'DASHBOARD' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mb-2">মোট বিক্রয়</p>
              <p className="text-4xl font-black text-emerald-700">৳ {orders.reduce((s, o) => s + o.total, 0)}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mb-2">মোট অর্ডার</p>
              <p className="text-4xl font-black">{orders.length}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mb-2">পণ্য সংখ্যা</p>
              <p className="text-4xl font-black">{products.length}</p>
            </div>
          </div>
        )}

        {activeTab === 'PRODUCTS' && (
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
              <h3 className="text-xl font-bold text-gray-800">পণ্যের তালিকা</h3>
              <button 
                onClick={() => { setEditingItem(null); setProductForm({name:'', price:'', unit:'কেজি', category: Category.VEGETABLES, image:'', description:'', stock:'100'}); setIsProductModalOpen(true); }}
                className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-emerald-700 transition-all shadow-md"
              >
                <Plus size={18}/> নতুন পণ্য
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  <tr><th className="p-6 text-left">নাম</th><th className="p-6 text-left">ক্যাটাগরি</th><th className="p-6 text-right">দাম</th><th className="p-6 text-right">অ্যাকশন</th></tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="p-6 font-bold text-gray-700">{p.name}</td>
                      <td className="p-6 text-xs text-gray-500 font-black">{p.category}</td>
                      <td className="p-6 text-right font-black text-emerald-800">৳ {p.price}</td>
                      <td className="p-6 text-right space-x-2">
                        <button onClick={() => { setEditingItem(p); setProductForm({name:p.name, price:p.price.toString(), unit:p.unit, category:p.category, image:p.image, description:p.description, stock:p.stock.toString()}); setIsProductModalOpen(true); }} className="text-blue-500 hover:bg-blue-50 p-2 rounded-xl transition-all"><Edit size={18}/></button>
                        <button onClick={() => deleteProduct(p.id)} className="text-red-500 hover:bg-red-50 p-2 rounded-xl transition-all"><Trash2 size={18}/></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {products.length === 0 && <p className="p-20 text-center text-gray-300 font-bold">কোনো পণ্য পাওয়া যায়নি</p>}
            </div>
          </div>
        )}

        {activeTab === 'SLIDES' && (
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
              <h3 className="text-xl font-bold text-gray-800">স্লাইডার ম্যানেজমেন্ট</h3>
              <button 
                onClick={() => { setEditingItem(null); setSlideForm({image:'', title:'', subtitle:'', buttonText:'বাজার শুরু করুন'}); setIsSlideModalOpen(true); }}
                className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2"
              >
                <Plus size={18}/> নতুন স্লাইড
              </button>
            </div>
            <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
              {slides.map(s => (
                <div key={s.id} className="group relative rounded-2xl overflow-hidden border border-gray-100 shadow-sm">
                  <img src={s.image} className="w-full h-40 object-cover opacity-80" alt="" />
                  <div className="p-4">
                    <h4 className="font-bold text-lg">{s.title}</h4>
                    <p className="text-xs text-gray-400 font-bold mt-1 truncate">{s.subtitle}</p>
                    <div className="mt-4 flex gap-2">
                      <button onClick={() => { setEditingItem(s); setSlideForm({image:s.image, title:s.title, subtitle:s.subtitle, buttonText:s.buttonText}); setIsSlideModalOpen(true); }} className="flex-1 bg-blue-50 text-blue-600 py-2 rounded-xl font-bold text-xs flex justify-center items-center gap-1 hover:bg-blue-100"><Edit size={14}/> এডিট</button>
                      <button onClick={() => deleteSlide(s.id)} className="flex-1 bg-red-50 text-red-600 py-2 rounded-xl font-bold text-xs flex justify-center items-center gap-1 hover:bg-red-100"><Trash2 size={14}/> ডিলিট</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'ORDERS' && (
          <div className="space-y-4">
