import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ShoppingCart, Store, Info, Phone, Search, Menu, X, ArrowRight, Settings, CheckCircle, MapPin, Heart, AlertTriangle, Eye, Bell } from 'lucide-react';
import { ViewType, Category, Product, CartItem, Order, Slide } from './types';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from './data';
import { supabase } from './supabase';
import AdminPanel from './components/AdminPanel';
import CartSidebar from './components/CartSidebar';
import ProductCard from './components/ProductCard';
import confetti from 'canvas-confetti';

// Simple Toast Component for Production UI
const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error', onClose: () => void }) => (
  <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-fade-in ${type === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
    {type === 'success' ? <CheckCircle size={20} /> : <AlertTriangle size={20} />}
    <span className="font-bold">{message}</span>
    <button onClick={onClose} className="ml-2 hover:opacity-70"><X size={16}/></button>
  </div>
);

const App: React.FC = () => {
  const [view, setView] = useState<ViewType | 'ORDER_SUCCESS' | 'SETUP_REQUIRED'>('STORE');
  const [products, setProducts] = useState<Product[]>([]);
  const [slides, setSlides] = useState<Slide[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isCartBouncing, setIsCartBouncing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const fetchData = async () => {
    try {
      const { data: prodData, error: prodError } = await supabase.from('products').select('*');
      const { data: slideData, error: slideError } = await supabase.from('slides').select('*');
      const { data: orderData } = await supabase.from('orders').select('*').order('date', { ascending: false });

      if (prodError?.code === '42P01') {
        setDbError('DATABASE_TABLES_MISSING');
        setView('SETUP_REQUIRED');
        return;
      }

      if (prodData) setProducts(prodData);
      if (slideData) setSlides(slideData);
      if (orderData) setOrders(orderData);
    } catch (error) {
      console.error('Fetch error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();

    // --- REAL-TIME SUBSCRIPTIONS ---
    const orderSubscription = supabase
      .channel('realtime_orders')
      .on('postgres_changes', { event: '*', table: 'orders' }, (payload) => {
        if (payload.eventType === 'INSERT') {
          setOrders(prev => [payload.new as Order, ...prev]);
          if (view === 'ADMIN') showToast('নতুন একটি অর্ডার এসেছে!', 'success');
        } else if (payload.eventType === 'UPDATE') {
          setOrders(prev => prev.map(o => o.id === payload.new.id ? { ...o, ...payload.new } : o));
        }
      })
      .subscribe();

    const productSubscription = supabase
      .channel('realtime_products')
      .on('postgres_changes', { event: '*', table: 'products' }, fetchData)
      .subscribe();

    return () => {
      supabase.removeChannel(orderSubscription);
      supabase.removeChannel(productSubscription);
    };
  }, [view]);

  useEffect(() => {
    if (view === 'STORE' && slides.length > 0) {
      const timer = setInterval(() => setCurrentSlide(prev => (prev + 1) % slides.length), 5000);
      return () => clearInterval(timer);
    }
  }, [view, slides.length]);

  const addToCart = useCallback((product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
    setIsCartBouncing(true);
    setTimeout(() => setIsCartBouncing(false), 500);
    showToast(`${product.name} ব্যাগে যোগ করা হয়েছে`);
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  }, []);

  const updateQuantity = useCallback((productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  }, []);

  const cartTotal = useMemo(() => cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0), [cart]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = activeCategory === Category.ALL || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [products, activeCategory, searchQuery]);

  const placeOrder = async (customerData: { name: string, phone: string, address: string }) => {
    const newOrder = {
      customerName: customerData.name,
      phone: customerData.phone,
      address: customerData.address,
      items: cart,
      total: cartTotal,
      status: 'Pending',
      date: new Date().toISOString()
    };

    const { data, error } = await supabase.from('orders').insert([newOrder]).select();

    if (error) {
      showToast('অর্ডার সেভ করতে সমস্যা হয়েছে। আবার চেষ্টা করুন।', 'error');
    } else {
      setCart([]);
      setView('ORDER_SUCCESS');
      confetti({
        particleCount: 150,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#059669', '#10b981', '#ffffff']
      });
    }
  };

  const NavItem: React.FC<{ label: string; viewTarget: ViewType; icon?: React.ReactNode }> = ({ label, viewTarget, icon }) => (
    <button 
      onClick={() => { setView(viewTarget); setIsMobileMenuOpen(false); window.scrollTo(0,0); }}
      className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-bold transition-all duration-300 ${
        view === viewTarget ? 'text-emerald-700 bg-emerald-50 shadow-sm border border-emerald-100' : 'text-gray-500 hover:text-emerald-600 hover:bg-gray-50'
      }`}
    >
      {icon}
      <span>{label}</span>
    </button>
  );

  if (isLoading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-white">
        <div className="w-16 h-16 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-emerald-800 font-bold animate-pulse tracking-widest uppercase text-xs">Samsul Grocery is Loading...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col selection:bg-emerald-100 font-sans">
      {/* Toast Notification Layer */}
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div className="bg-emerald-800 text-white text-[10px] md:text-xs py-2 px-4 text-center font-bold tracking-[0.2em] uppercase">
        বদলগাছী সদরে ১ ঘণ্টার মধ্যে হোম ডেলিভারি ফ্রি! আজই অর্ডার করুন।
      </div>

      <header className="sticky top-0 z-40 bg-white/90 backdrop-blur-xl border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20 gap-4">
            <div className="flex items-center gap-4 cursor-pointer shrink-0" onClick={() => setView('STORE')}>
              <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg transition-transform active:scale-90"><Store size={26} /></div>
              <div className="hidden sm:block">
                <h1 className="text-xl font-black text-emerald-900 leading-none tracking-tight">সামসুল'স গ্রোসরি</h1>
                <p className="text-[10px] text-gray-400 font-bold mt-1 flex items-center gap-1 uppercase tracking-tighter"><MapPin size={10}/> বদলগাছী, নওগাঁ</p>
              </div>
            </div>

            {view === 'STORE' && (
              <div className="hidden md:flex flex-grow max-w-xl relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text"
                  placeholder="আপনার প্রিয় পণ্যটি খুঁজুন..."
                  className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl py-3 pl-12 pr-4 outline-none transition-all font-medium text-sm shadow-inner"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
            )}

            <div className="flex items-center gap-2 md:gap-4">
              <nav className="hidden lg:flex items-center gap-1">
                <NavItem label="হোম" viewTarget="STORE" icon={<Store size={18} />} />
                <NavItem label="অ্যাডমিন" viewTarget="ADMIN" icon={<Settings size={18} />} />
              </nav>

              <button 
                onClick={() => setIsCartOpen(true)} 
                className={`group relative p-3 text-gray-700 hover:bg-emerald-50 rounded-2xl transition-all active:scale-95 ${isCartBouncing ? 'scale-110' : 'scale-100'}`}
              >
                <ShoppingCart size={24} className="group-hover:text-emerald-600" />
                {cart.length > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-black w-6 h-6 flex items-center justify-center rounded-full border-4 border-white shadow-sm">
                    {cart.length}
                  </span>
                )}
              </button>

              <button className="lg:hidden p-3 text-gray-700" onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Floating Cart for Mobile */}
      {cart.length > 0 && !isCartOpen && view === 'STORE' && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className={`fixed bottom-6 right-6 z-50 md:hidden bg-emerald-600 text-white p-5 rounded-full shadow-2xl flex items-center gap-3 animate-fade-in ${isCartBouncing ? 'scale-110' : 'scale-100'}`}
        >
          <ShoppingCart size={24} />
          <span className="font-black">৳ {cartTotal}</span>
        </button>
      )}

      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 top-20 bg-white z-50 p-6 animate-fade-in border-t shadow-2xl">
          <nav className="flex flex-col gap-3">
            <NavItem label="হোম পেজ" viewTarget="STORE" icon={<Store size={22} />} />
            <NavItem label="আমাদের সম্পর্কে" viewTarget="ABOUT" icon={<Info size={22} />} />
            <NavItem label="অ্যাডমিন প্যানেল" viewTarget="ADMIN" icon={<Settings size={22} />} />
          </nav>
        </div>
      )}

      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="animate-fade-in">
            <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8">
              {slides.length > 0 && (
                <div className="relative rounded-[2.5rem] overflow-hidden mb-10 h-72 md:h-[500px] shadow-2xl bg-emerald-900 group">
                  {slides.map((slide, index) => (
                    <div key={slide.id} className={`absolute inset-0 transition-all duration-1000 ease-out ${index === currentSlide ? 'opacity-100 scale-100' : 'opacity-0 scale-105 pointer-events-none'}`}>
                      <img src={slide.image} alt={slide.title} className="w-full h-full object-cover opacity-50" />
                      <div className="absolute inset-0 bg-gradient-to-r from-emerald-950/95 via-emerald-900/40 to-transparent flex flex-col justify-center px-8 md:px-20">
                        <span className="text-emerald-400 font-black text-xs md:text-sm uppercase tracking-[0.4em] mb-4">Samsul's Exclusive</span>
                        <h2 className="text-3xl md:text-6xl font-black text-white mb-6 leading-tight max-w-2xl">{slide.title}</h2>
                        <p className="text-emerald-100/90 text-sm md:text-xl mb-10 max-w-lg font-medium">{slide.subtitle}</p>
                        <button onClick={() => document.getElementById('products-grid')?.scrollIntoView({ behavior: 'smooth' })} className="bg-white text-emerald-900 px-10 py-4 rounded-2xl font-black w-fit shadow-xl">{slide.buttonText}</button>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              <div className="mb-10">
                <div className="flex gap-4 overflow-x-auto no-scrollbar pb-4 -mx-4 px-4">
                  {Object.values(Category).map(cat => (
                    <button
                      key={cat}
                      onClick={() => setActiveCategory(cat)}
                      className={`px-8 py-3.5 rounded-2xl font-black whitespace-nowrap transition-all border-2 text-sm ${
                        activeCategory === cat 
                        ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl' 
                        : 'bg-white border-gray-100 text-gray-500 hover:text-emerald-600'
                      }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>

              <div id="products-grid" className="scroll-mt-32">
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 md:gap-8">
                  {filteredProducts.map(product => (
                    <ProductCard 
                      key={product.id} 
                      product={product} 
                      onAddToCart={addToCart} 
                      onQuickView={() => setSelectedProduct(product)}
                    />
                  ))}
                </div>
                {filteredProducts.length === 0 && (
                  <div className="py-24 text-center">
                    <p className="text-2xl font-black text-gray-300">কোনো পণ্য পাওয়া যায়নি!</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {view === 'CHECKOUT' && (
          <div className="max-w-xl mx-auto py-20 px-4 animate-fade-in">
            <h2 className="text-4xl font-black mb-10 text-center text-emerald-900">চেকআউট</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              placeOrder({
                name: fd.get('name') as string,
                phone: fd.get('phone') as string,
                address: fd.get('address') as string,
              });
            }} className="bg-white p-10 rounded-[3rem] shadow-2xl space-y-6">
              <input name="name" required className="w-full p-4 bg-gray-50 border rounded-2xl font-bold" placeholder="আপনার নাম" />
              <input name="phone" required type="tel" className="w-full p-4 bg-gray-50 border rounded-2xl font-bold" placeholder="মোবাইল নম্বর" />
              <textarea name="address" required className="w-full p-4 bg-gray-50 border rounded-2xl font-bold" placeholder="ঠিকানা" rows={3}></textarea>
              <div className="pt-6 border-t">
                <div className="flex justify-between items-center mb-6">
                  <span className="text-gray-500 font-bold">মোট বিল:</span>
                  <span className="text-3xl font-black text-emerald-800">৳ {cartTotal}</span>
                </div>
                <button className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl hover:bg-emerald-700 transition-all">
                  অর্ডার কনফার্ম করুন
                </button>
              </div>
            </form>
          </div>
        )}

        {view === 'ORDER_SUCCESS' && (
          <div className="max-w-2xl mx-auto py-32 px-4 text-center animate-fade-in">
            <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 shadow-2xl">
              <CheckCircle size={72} strokeWidth={2.5} />
            </div>
            <h2 className="text-5xl font-black text-emerald-900 mb-6 tracking-tight">অর্ডার সফল হয়েছে!</h2>
            <p className="text-gray-500 text-xl mb-12 font-medium leading-relaxed">ধন্যবাদ! আমরা খুব শীঘ্রই ডেলিভারির জন্য আপনার সাথে যোগাযোগ করব। আমাদের ওপর আস্থা রাখার জন্য কৃতজ্ঞ।</p>
            <button onClick={() => setView('STORE')} className="bg-emerald-600 text-white px-12 py-5 rounded-2xl font-black text-xl shadow-xl hover:bg-emerald-700 transition-all shadow-emerald-200">আরো বাজার করুন</button>
          </div>
        )}

        {view === 'ADMIN' && (
          <AdminPanel 
            products={products} setProducts={setProducts} 
            slides={slides} setSlides={setSlides}
            orders={orders} setOrders={setOrders}
            needsSetup={dbError === 'DATABASE_TABLES_MISSING'}
          />
        )}

        {view === 'ABOUT' && (
          <div className="max-w-4xl mx-auto py-20 px-6 animate-fade-in text-center">
            <h2 className="text-5xl font-black text-emerald-900 mb-10">আমাদের লক্ষ্য</h2>
            <p className="text-xl text-gray-600 leading-relaxed max-w-2xl mx-auto font-medium">বদলগাছীর সাধারণ মানুষের নিত্যদিনের বাজারকে সহজ, দ্রুত এবং আধুনিক করতে আমাদের পথচলা। আমরা সরাসরি খামারি ও কৃষকদের থেকে তাজা পণ্য আপনার কাছে পৌঁছে দিই। আপনার সুস্বাস্থ্যই আমাদের সার্থকতা।</p>
          </div>
        )}

        {view === 'SETUP_REQUIRED' && (
          <div className="min-h-screen bg-emerald-50 flex items-center justify-center p-6">
            <div className="max-w-2xl w-full bg-white rounded-[3rem] shadow-2xl p-12 text-center">
              <AlertTriangle size={48} className="text-amber-500 mx-auto mb-8" />
              <h2 className="text-4xl font-black text-emerald-900 mb-4">ডেটাবেস সেটআপ প্রয়োজন</h2>
              <p className="text-gray-500 mb-10 font-medium leading-relaxed">আপনার Supabase প্রজেক্টে এখনও প্রয়োজনীয় টেবিলগুলো তৈরি করা হয়নি। অ্যাডমিন প্যানেলে গিয়ে সেটিংস ট্যাব থেকে সেটআপ সম্পন্ন করুন।</p>
              <button onClick={() => setView('ADMIN')} className="bg-emerald-600 text-white px-10 py-4 rounded-2xl font-black text-xl shadow-lg shadow-emerald-100 transition-all active:scale-95">সেটআপ প্যানেলে যান</button>
            </div>
          </div>
        )}
      </main>

      {/* Product Detail Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-fade-in flex flex-col md:flex-row max-h-[90vh] overflow-y-auto">
            <div className="w-full md:w-1/2 aspect-square relative">
              <img src={selectedProduct.image} alt={selectedProduct.name} className="w-full h-full object-cover" />
              <button onClick={() => setSelectedProduct(null)} className="absolute top-6 left-6 bg-white/80 p-2 rounded-full md:hidden shadow-lg"><X/></button>
            </div>
            <div className="w-full md:w-1/2 p-10 flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-4">
                  <span className="bg-emerald-100 text-emerald-700 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest">{selectedProduct.category}</span>
                  <button onClick={() => setSelectedProduct(null)} className="hidden md:block p-2 hover:bg-gray-100 rounded-full transition-all"><X/></button>
                </div>
                <h3 className="text-3xl font-black text-gray-900 mb-2">{selectedProduct.name}</h3>
                <p className="text-gray-500 font-medium mb-6 leading-relaxed text-lg">{selectedProduct.description}</p>
                <div className="flex items-end gap-2 mb-10">
                  <span className="text-4xl font-black text-emerald-800">৳ {selectedProduct.price}</span>
                  <span className="text-gray-400 font-bold mb-1 uppercase text-xs">প্রতি {selectedProduct.unit}</span>
                </div>
              </div>
              <button 
                onClick={() => { addToCart(selectedProduct); setSelectedProduct(null); setIsCartOpen(true); }}
                className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl shadow-emerald-200 hover:bg-emerald-700 active:scale-95 transition-all flex items-center justify-center gap-3"
              >
                <ShoppingCart /> ব্যাগে যোগ করুন
              </button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-gray-950 text-white py-20 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <h1 className="text-3xl font-black mb-4 tracking-tight">সামসুল'স গ্রোসরি</h1>
          <p className="text-gray-400 mb-8 font-medium">বদলগাছী বাজার রোড, নওগাঁ, বাংলাদেশ</p>
          <div className="flex justify-center gap-6 mb-12">
            <a href="tel:01700000000" className="flex items-center gap-2 text-emerald-400 font-bold hover:scale-105 transition-transform"><Phone size={20}/> ০১৭০০-০০০০০০</a>
          </div>
          <p className="text-[10px] text-gray-600 uppercase tracking-[0.5em] font-bold">© ২০২৪ SAMSUL GROCERY - ALL RIGHTS RESERVED</p>
        </div>
      </footer>

      <CartSidebar 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} 
        cart={cart} updateQuantity={updateQuantity} 
        removeFromCart={removeFromCart} onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />
    </div>
  );
};

export default App;

export enum Category {
  RICE = 'চাল',
  OIL = 'তেল',
  VEGETABLES = 'শাক-সবজি',
  FRUITS = 'ফল',
  SNACKS = 'নাস্তা',
  BEVERAGES = 'পানীয়',
  HOUSEHOLD = 'গৃহস্থালি',
  ALL = 'সব পণ্য'
}

export interface Product {
  id: string;
  name: string;
  price: number;
  unit: string;
  category: Category;
  image: string;
  description: string;
  stock: number;
}

export interface Slide {
  id: string;
  image: string;
  title: string;
  subtitle: string;
  buttonText: string;
}

export interface CartItem {
  product: Product;
  quantity: number;
}

export interface Order {
  id: string;
  customerName: string;
  phone: string;
  address: string;
  items: CartItem[];
  total: number;
  status: 'Pending' | 'Delivered' | 'Cancelled';
  date: string;
}

export type ViewType = 'STORE' | 'ADMIN' | 'CHECKOUT' | 'ABOUT' | 'ORDER_SUCCESS' | 'SETUP_REQUIRED';

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ShoppingCart, Store, Info, Phone, Search, Menu, X, Settings, CheckCircle, MapPin, AlertTriangle } from 'lucide-react';
import { ViewType, Category, Product, CartItem, Order, Slide } from './types';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from './data';
import { supabase } from './supabase';
import AdminPanel from './components/AdminPanel';
import CartSidebar from './components/CartSidebar';
import ProductCard from './components/ProductCard';
import confetti from 'canvas-confetti';

const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error', onClose: () => void }) => (
  <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-fade-in ${type === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
    {type === 'success' ? <CheckCircle size={20} /> : <AlertTriangle size={20} />}
    <span className="font-bold">{message}</span>
    <button onClick={onClose} className="ml-2 hover:opacity-70"><X size={16}/></button>
  </div>
);

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('STORE');
  const [products, setProducts] = useState<Product[]>([]);
  const [slides, setSlides] = useState<Slide[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [dbError, setDbError] = useState<boolean>(false);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isCartBouncing, setIsCartBouncing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const fetchData = async () => {
    try {
      const { data: prodData, error: prodError } = await supabase.from('products').select('*');
      const { data: slideData, error: slideError } = await supabase.from('slides').select('*');
      const { data: orderData } = await supabase.from('orders').select('*').order('date', { ascending: false });

      if (prodError?.code === '42P01') {
        setDbError(true);
        setView('SETUP_REQUIRED');
        return;
      }

      setProducts(prodData || INITIAL_PRODUCTS);
      setSlides(slideData || INITIAL_SLIDES);
      setOrders(orderData || []);
    } catch (error) {
      console.error('Fetch error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();

    // --- REAL-TIME ENABLED ---
    const channels = supabase.channel('schema-db-changes')
      .on('postgres_changes', { event: '*', table: 'orders' }, (payload) => {
        if (payload.eventType === 'INSERT') {
          setOrders(prev => [payload.new as Order, ...prev]);
          if (view === 'ADMIN') showToast('নতুন একটি অর্ডার এসেছে!', 'success');
        } else if (payload.eventType === 'UPDATE') {
          setOrders(prev => prev.map(o => o.id === payload.new.id ? { ...o, ...payload.new } : o));
        }
      })
      .on('postgres_changes', { event: '*', table: 'products' }, fetchData)
      .subscribe();

    return () => { supabase.removeChannel(channels); };
  }, [view]);

  // Stable Slideshow Effect
  useEffect(() => {
    if (view === 'STORE' && slides.length > 1) {
      const timer = setInterval(() => {
        setCurrentSlide(prev => (prev + 1) % slides.length);
      }, 5000);
      return () => clearInterval(timer);
    }
  }, [view, slides.length]);

  const addToCart = useCallback((product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
    setIsCartBouncing(true);
    setTimeout(() => setIsCartBouncing(false), 500);
    showToast(`${product.name} যোগ করা হয়েছে`);
  }, []);

  const cartTotal = useMemo(() => cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0), [cart]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = activeCategory === Category.ALL || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [products, activeCategory, searchQuery]);

  const placeOrder = async (customerData: { name: string, phone: string, address: string }) => {
    const newOrder = {
      customerName: customerData.name,
      phone: customerData.phone,
      address: customerData.address,
      items: cart,
      total: cartTotal,
      status: 'Pending',
      date: new Date().toISOString()
    };

    const { error } = await supabase.from('orders').insert([newOrder]);

    if (error) {
      showToast('অর্ডার দিতে ব্যর্থ হয়েছে। ইন্টারনেট চেক করুন।', 'error');
    } else {
      setCart([]);
      setView('ORDER_SUCCESS');
      confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-white">
        <div className="w-12 h-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-emerald-800 font-bold tracking-widest uppercase text-xs">Loading Store...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col font-sans bg-gray-50">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 h-20 flex justify-between items-center gap-4">
          <div className="flex items-center gap-3 cursor-pointer shrink-0" onClick={() => setView('STORE')}>
            <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg"><Store size={24} /></div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-emerald-900 leading-none">সামসুল'স গ্রোসরি</h1>
              <p className="text-[10px] text-gray-400 font-bold flex items-center gap-1 uppercase tracking-tighter mt-1"><MapPin size={10}/> বদলগাছী, নওগাঁ</p>
            </div>
          </div>

          {view === 'STORE' && (
            <div className="hidden md:flex flex-grow max-w-xl relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="text"
                placeholder="কি খুঁজতে চাচ্ছেন?"
                className="w-full bg-gray-100 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl py-3 pl-12 pr-4 outline-none transition-all font-medium text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          )}

          <div className="flex items-center gap-4">
            <nav className="hidden lg:flex items-center gap-2">
              <button onClick={() => setView('STORE')} className={`px-4 py-2 rounded-xl font-bold ${view === 'STORE' ? 'text-emerald-700 bg-emerald-50' : 'text-gray-500'}`}>হোম</button>
              <button onClick={() => setView('ADMIN')} className={`px-4 py-2 rounded-xl font-bold ${view === 'ADMIN' ? 'text-emerald-700 bg-emerald-50' : 'text-gray-500'}`}>অ্যাডমিন</button>
            </nav>
            <button 
              onClick={() => setIsCartOpen(true)} 
              className={`relative p-3 bg-gray-100 hover:bg-emerald-50 rounded-2xl transition-all ${isCartBouncing ? 'scale-110' : ''}`}
            >
              <ShoppingCart size={22} className="text-gray-700" />
              {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">{cart.length}</span>}
            </button>
            <button className="lg:hidden p-2" onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}><Menu size={24} /></button>
          </div>
        </div>
      </header>

      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-[60] bg-white p-6 animate-fade-in flex flex-col">
          <div className="flex justify-end mb-8"><button onClick={() => setIsMobileMenuOpen(false)}><X size={32}/></button></div>
          <nav className="flex flex-col gap-4">
            <button onClick={() => {setView('STORE'); setIsMobileMenuOpen(false);}} className="text-2xl font-black text-emerald-900 border-b pb-4">হোম পেজ</button>
            <button onClick={() => {setView('ADMIN'); setIsMobileMenuOpen(false);}} className="text-2xl font-black text-emerald-900 border-b pb-4">অ্যাডমিন প্যানেল</button>
            <button onClick={() => {setView('ABOUT'); setIsMobileMenuOpen(false);}} className="text-2xl font-black text-emerald-900 border-b pb-4">আমাদের সম্পর্কে</button>
          </nav>
        </div>
      )}

      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="animate-fade-in">
            <div className="max-w-7xl mx-auto px-4 py-6">
              {slides.length > 0 && (
                <div className="relative rounded-[2.5rem] overflow-hidden mb-8 h-[250px] md:h-[450px] shadow-xl bg-emerald-900">
                  {slides.map((slide, index) => (
                    <div key={slide.id} className={`absolute inset-0 transition-opacity duration-1000 ${index === currentSlide ? 'opacity-100' : 'opacity-0'}`}>
                      <img src={slide.image} className="w-full h-full object-cover opacity-40" alt="" />
                      <div className="absolute inset-0 flex flex-col justify-center px-8 md:px-20">
                        <h2 className="text-2xl md:text-5xl font-black text-white mb-4 max-w-xl">{slide.title}</h2>
                        <p className="text-emerald-100 mb-8 text-sm md:text-lg max-w-md">{slide.subtitle}</p>
                        <button onClick={() => document.getElementById('products')?.scrollIntoView({behavior:'smooth'})} className="bg-white text-emerald-900 px-8 py-3 rounded-xl font-black w-fit">{slide.buttonText}</button>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              <div className="flex gap-3 overflow-x-auto no-scrollbar pb-6">
                {Object.values(Category).map(cat => (
                  <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-6 py-2.5 rounded-xl font-bold whitespace-nowrap border-2 transition-all ${activeCategory === cat ? 'bg-emerald-600 border-emerald-600 text-white' : 'bg-white border-gray-100 text-gray-500'}`}>{cat}</button>
                ))}
              </div>

              <div id="products" className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4 md:gap-6">
                {filteredProducts.map(p => (
                  <ProductCard key={p.id} product={p} onAddToCart={addToCart} onQuickView={() => setSelectedProduct(p)} />
                ))}
              </div>
            </div>
          </div>
        )}

        {view === 'CHECKOUT' && (
          <div className="max-w-xl mx-auto py-16 px-4 animate-fade-in">
            <h2 className="text-3xl font-black mb-8 text-emerald-900">অর্ডার নিশ্চিত করুন</h2>
