                <h3 className="text-2xl font-black mb-2">{selectedProduct.name}</h3>
                <p className="text-gray-500 mb-6">{selectedProduct.description}</p>
                <div className="text-3xl font-black text-emerald-800 mb-8">৳ {selectedProduct.price} <span className="text-sm font-bold text-gray-400">/ {selectedProduct.unit}</span></div>
              </div>
              <button onClick={() => { addToCart(selectedProduct); setSelectedProduct(null); setIsCartOpen(true); }} className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black flex items-center justify-center gap-2"><ShoppingCart size={20}/> ব্যাগে যোগ করুন</button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-gray-950 text-white py-12 text-center">
        <h2 className="text-2xl font-black mb-4">সামসুল'স গ্রোসরি</h2>
        <p className="text-gray-500 mb-8">বদলগাছী বাজার, নওগাঁ | ফোন: ০১৭০০-০০০০০০</p>
        <div className="text-[10px] text-gray-700 font-bold uppercase tracking-widest">© ২০২৪ সর্বস্বত্ব সংরক্ষিত</div>
      </footer>

      <CartSidebar 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} 
        cart={cart} updateQuantity={(id, d) => setCart(prev => prev.map(i => i.product.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} 
        removeFromCart={(id) => setCart(prev => prev.filter(i => i.product.id !== id))} 
        onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />
    </div>
  );
};

