}

const AdminPanel: React.FC<AdminPanelProps> = ({ products, setProducts, slides, setSlides, orders, setOrders, needsSetup = false }) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'PRODUCTS' | 'ORDERS' | 'SLIDES' | 'SETTINGS'>(needsSetup ? 'SETTINGS' : 'DASHBOARD');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [isSeeding, setIsSeeding] = useState(false);
  const [copied, setCopied] = useState(false);

  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [productForm, setProductForm] = useState({ name: '', price: '', unit: 'কেজি', category: Category.VEGETABLES, image: '', description: '' });

  const sqlSchema = `CREATE TABLE products (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, name text, price float8, unit text, category text, image text, description text, created_at timestamptz DEFAULT now());
CREATE TABLE slides (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, image text, title text, subtitle text, buttonText text, created_at timestamptz DEFAULT now());
CREATE TABLE orders (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, customerName text, phone text, address text, items jsonb, total float8, status text DEFAULT 'Pending', date timestamptz DEFAULT now());
ALTER TABLE products DISABLE ROW LEVEL SECURITY;
ALTER TABLE slides DISABLE ROW LEVEL SECURITY;
ALTER TABLE orders DISABLE ROW LEVEL SECURITY;`;

  const seedData = async () => {
    setIsSeeding(true);
    try {
      await supabase.from('products').insert(INITIAL_PRODUCTS.map(({id, ...r}) => r));
      await supabase.from('slides').insert(INITIAL_SLIDES.map(({id, ...r}) => r));
      alert('ডেমো ডেটা সেভ হয়েছে!');
      window.location.reload();
    } catch (e) { alert('ত্রুটি হয়েছে'); }
    finally { setIsSeeding(false); }
  };

  const deleteProduct = async (id: string) => {
    if(confirm('মুছে ফেলতে চান?')) {
      const { error } = await supabase.from('products').delete().eq('id', id);
      if(!error) setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="max-w-md mx-auto my-20 p-8 bg-white rounded-3xl shadow-xl text-center">
        <h2 className="text-2xl font-black mb-6">অ্যাডমিন লগইন</h2>
        <input type="password" value={password} onChange={e => setPassword(e.target.value)} className="w-full p-4 border rounded-xl mb-4 font-bold" placeholder="পাসওয়ার্ড" />
        <button onClick={() => { if(password === 'admin123') setIsAuthenticated(true); else alert('ভুল পাসওয়ার্ড'); }} className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold">প্রবেশ করুন</button>
        <p className="mt-4 text-xs text-gray-400">Hint: admin123</p>
