        <button onClick={() => setActiveTab('PRODUCTS')} className={`w-full text-left px-6 py-3 rounded-xl font-bold flex items-center gap-3 ${activeTab === 'PRODUCTS' ? 'bg-emerald-600 text-white' : 'hover:bg-gray-100'}`}><Package size={18}/> পণ্য তালিকা</button>
        <button onClick={() => setActiveTab('ORDERS')} className={`w-full text-left px-6 py-3 rounded-xl font-bold flex items-center gap-3 ${activeTab === 'ORDERS' ? 'bg-emerald-600 text-white' : 'hover:bg-gray-100'}`}><ClipboardList size={18}/> অর্ডারসমূহ</button>
        <button onClick={() => setActiveTab('SETTINGS')} className={`w-full text-left px-6 py-3 rounded-xl font-bold flex items-center gap-3 ${activeTab === 'SETTINGS' ? 'bg-emerald-600 text-white' : 'hover:bg-gray-100'}`}><Database size={18}/> সেটিংস</button>
        <button onClick={() => setIsAuthenticated(false)} className="w-full text-left px-6 py-3 rounded-xl font-bold text-red-500 mt-8 flex items-center gap-3"><LogOut size={18}/> লগআউট</button>
