              <p className="text-gray-400 font-bold text-xs uppercase mb-1">মোট বিক্রয়</p>
              <p className="text-4xl font-black text-emerald-800">৳ {orders.reduce((s,o) => s + o.total, 0)}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl shadow-sm border">
              <p className="text-gray-400 font-bold text-xs uppercase mb-1">সক্রিয় অর্ডার</p>
              <p className="text-4xl font-black text-amber-600">{orders.filter(o => o.status === 'Pending').length}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl shadow-sm border">
              <p className="text-gray-400 font-bold text-xs uppercase mb-1">মোট পণ্য</p>
              <p className="text-4xl font-black">{products.length}</p>
