            <p className="text-gray-500 font-medium">বদলগাছী সদর, নওগাঁ | ফোন: ০১৭০০-০০০০০০</p>
          </div>
          <div className="flex flex-wrap justify-center gap-6 text-sm font-bold text-gray-400 mb-12">
            <button onClick={() => setView('STORE')} className="hover:text-emerald-400 transition">হোম</button>
            <button onClick={() => setView('ABOUT')} className="hover:text-emerald-400 transition">আমাদের সম্পর্কে</button>
            <button onClick={() => setView('ADMIN')} className="hover:text-emerald-400 transition">অ্যাডমিন</button>
          </div>
          <div className="border-t border-gray-900 pt-8">
            <p className="text-[10px] text-gray-700 font-bold uppercase tracking-[0.5em]">© ২০২৪ SAMSUL GROCERY - ALL RIGHTS RESERVED</p>
          </div>
        </div>
      </footer>

      <CartSidebar 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} 
        cart={cart} updateQuantity={(id, d) => setCart(prev => prev.map(i => i.product.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} 
        removeFromCart={(id) => setCart(prev => prev.filter(i => i.product.id !== id))} 
        onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Package, ClipboardList, TrendingUp, LogOut, Plus, Trash2, X, Database, Copy, CheckCircle2, RefreshCw, CheckCircle, Clock, AlertCircle } from 'lucide-react';
import { Product, Order, Slide, Category } from '../types';
import { supabase } from '../supabase';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from '../data';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  slides: Slide[];
  setSlides: React.Dispatch<React.SetStateAction<Slide[]>>;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  needsSetup?: boolean;
  fetchData: () => Promise<void>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ products, setProducts, slides, setSlides, orders, setOrders, needsSetup = false, fetchData }) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'PRODUCTS' | 'ORDERS' | 'SETTINGS'>(needsSetup ? 'SETTINGS' : 'DASHBOARD');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [isSeeding, setIsSeeding] = useState(false);
  const [copied, setCopied] = useState(false);
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [productForm, setProductForm] = useState({ name: '', price: '', unit: 'কেজি', category: Category.VEGETABLES, image: '', description: '' });

  const stats = useMemo(() => {
    const totalSales = orders.filter(o => o.status === 'Delivered').reduce((sum, o) => sum + o.total, 0);
    const pendingOrders = orders.filter(o => o.status === 'Pending').length;
    return { totalSales, pendingOrders, totalOrders: orders.length };
  }, [orders]);

  const sqlSchema = `-- ১. টেবিলগুলো তৈরি করুন
CREATE TABLE products (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, name text, price float8, unit text, category text, image text, description text, created_at timestamptz DEFAULT now());
CREATE TABLE slides (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, image text, title text, subtitle text, buttonText text, created_at timestamptz DEFAULT now());
CREATE TABLE orders (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, customerName text, phone text, address text, items jsonb, total float8, status text DEFAULT 'Pending', date timestamptz DEFAULT now());

-- ২. সিকিউরিটি বন্ধ করুন (পাবলিক এক্সেস)
ALTER TABLE products DISABLE ROW LEVEL SECURITY;
ALTER TABLE slides DISABLE ROW LEVEL SECURITY;
ALTER TABLE orders DISABLE ROW LEVEL SECURITY;

-- ৩. রিয়েল-টাইম এনাবল করুন (ড্যাশবোর্ডের Replication সেকশনে গিয়ে এগুলো চেক করুন)`;

  const seedData = async () => {
    setIsSeeding(true);
    try {
      await supabase.from('products').insert(INITIAL_PRODUCTS.map(({id, ...r}) => r));
      await supabase.from('slides').insert(INITIAL_SLIDES.map(({id, ...r}) => r));
      alert('ডেমো ডেটা সফলভাবে যোগ হয়েছে!');
      fetchData();
    } catch (e) { alert('সেটআপ করতে সমস্যা হয়েছে। ডাটাবেস টেবিল আগে তৈরি করুন।'); }
    finally { setIsSeeding(false); }
  };

  const updateOrderStatus = async (id: string, newStatus: 'Pending' | 'Delivered' | 'Cancelled') => {
    const { error } = await supabase.from('orders').update({ status: newStatus }).eq('id', id);
    if (error) alert('স্ট্যাটাস আপডেট হয়নি');
  };

  const deleteProduct = async (id: string) => {
    if(confirm('আপনি কি নিশ্চিতভাবে এই পণ্যটি মুছে ফেলতে চান?')) {
      const { error } = await supabase.from('products').delete().eq('id', id);
      if(!error) fetchData();
    }
  };

  const saveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    const { error } = await supabase.from('products').insert([productForm]);
    if (!error) {
      setIsProductModalOpen(false);
      setProductForm({ name: '', price: '', unit: 'কেজি', category: Category.VEGETABLES, image: '', description: '' });
      fetchData();
